for (const item of $input.all()) {
  let imageUrl = null;

  // 1. Intentamos sacar la imagen del "enclosure" (tu ejemplo)
  if (item.json.enclosure && item.json.enclosure.url) {
    imageUrl = item.json.enclosure.url;
  } 
  // 2. Si no hay enclosure, buscamos dentro de "content:encoded" o "content"
  else {
    const content = item.json['content:encoded'] || item.json.content || '';
    // Usamos una expresión regular para encontrar la etiqueta <img> y sacar su src
    const imgRegex = /<img[^>]+src="([^">]+)"/i;
    const match = content.match(imgRegex);

    if (match && match[1]) {
      imageUrl = match[1];
    }
  }

  // 3. Añadimos la URL extraída al objeto final con el nombre "image"
  item.json.image = imageUrl;
}

return $input.all();

for (const item of $input.all()) {
  // Comprobamos que el item tenga un título para evitar errores
  if (item.json.title) {
    // Pasamos el título a minúsculas temporalmente para que detecte "Insider", "INSIDER", etc.
    const tituloMinusculas = item.json.title.toLowerCase();

    // Si el título incluye "insider", le añadimos "UDIA " al principio
    if (tituloMinusculas.includes("insider")) {
      item.json.title = "UDIA " + item.json.title;
    }
  }
}

// Devolvemos todos los elementos (modificados o no) al siguiente nodo
return $input.all();
